-- Phase 13 演示数据增强（幂等，使用固定ID）
USE fixed_asset_lifecycle_system;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- 清理旧DEMO数据（同时按ID和编号前缀清理）
DELETE FROM inventory_record WHERE task_id IN (SELECT id FROM inventory_task WHERE task_code LIKE 'DEMO-%') OR task_id >= 1000;
DELETE FROM inventory_task WHERE task_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM approval_record WHERE instance_id IN (SELECT id FROM approval_instance WHERE business_id IN (SELECT id FROM asset_receive_order WHERE order_code LIKE 'DEMO-%')) OR instance_id >= 1000;
DELETE FROM approval_instance WHERE business_id IN (SELECT id FROM asset_receive_order WHERE order_code LIKE 'DEMO-%') OR id >= 1000;
DELETE FROM asset_scrap_order WHERE order_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset_repair_order WHERE order_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset_transfer_order WHERE order_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset_receive_order WHERE order_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset_inbound_order WHERE order_code LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset_operation_log WHERE asset_id IN (SELECT id FROM asset WHERE asset_code LIKE 'DEMO-%') OR id >= 1000;
DELETE FROM depreciation_record WHERE asset_id IN (SELECT id FROM asset WHERE asset_code LIKE 'DEMO-%') OR id >= 1000;
DELETE FROM finance_sync_record WHERE sync_batch_no LIKE 'DEMO-%' OR id >= 1000;
DELETE FROM asset WHERE asset_code LIKE 'DEMO-%' OR id >= 1000;

